import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      { name: 'Desktops', data: [10, 16, 12, 18, 13, 20, 15, 22, 17] },
      { name: 'Tablets', data: [38, 45, 40, 47, 42, 49, 44, 51, 46] },
      { name: 'Phones', data: [66, 73, 68, 75, 70, 77, 72, 79, 74] },
      { name: 'Watches', data: [94, 101, 96, 103, 98, 105, 100, 107, 102] },
      {
        name: 'Projectors',
        data: [122, 129, 124, 131, 126, 133, 128, 135, 130],
      },
    ],
    options: {
      chart: {
        height: 380,
        width: '100%',
        type: 'line',
      },
      tooltip: {
        shared: true,
      },
      markers: {
        size: 5,
      },
      stroke: {
        curve: 'straight',
      },
      title: {
        text: 'Shared tooltip: click reports the clicked series',
        align: 'left',
      },
      xaxis: {
        categories: [
          'Jan',
          'Feb',
          'Mar',
          'Apr',
          'May',
          'Jun',
          'Jul',
          'Aug',
          'Sep',
        ],
      },
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="line"
          height={380}
        />
      </div>
    </div>
  )
}

export default ApexChart
